);
     eb.embedding = Some(next_emb());
     queryable.insert(&eb).await.unwrap();

     // 8 filler entries for HNSW connectivity
     for i in 0..8 {
         let mut filler = KnowledgeEntry::new(
             format!("filler {i}"),
             "reinforce-scope".to_string(),
             "v1".to_string(),
