         expand_graph: true,
         graph_depth: 1,
         visibility: VisibilityMode::All,
         ..Default::default()
     };

     let result = retriever
         .retrieve("auth", "reinforce-scope", &opts_graph)
         .await
         .unwrap();

     // Both A and B are in vector results, and A→B edge exists,
